  <text x="296" y="232" fill="#eab308" font-family="sans-serif" font-size="15" font-weight="700">+2.22%</text>
  <line x1="20" y1="252" x2="680" y2="252" stroke="#3f3f46" stroke-width="1"/>
  <rect x="20" y="266" width="205" height="140" rx="10" fill="#18181b" stroke="#3f3f46"/>
  <text x="40" y="294" fill="#a1a1aa" font-family="sans-serif" font-size="13">July 29 FOMC Hike Odds</text>
